INSERT INTO public.state_law_provisions
  (act_id, state_code, topic, rule_kind, threshold_numeric, threshold_unit, summary, statute_citation, source_url, source_date, effective_year)
SELECT a.id, 'NC', v.topic, v.rule_kind, v.threshold_numeric, v.threshold_unit, v.summary, v.citation, v.url, DATE '2026-06-11', 2026
FROM public.state_landlord_tenant_acts a CROSS JOIN (VALUES
  ('late_fee_max_pct', 'max', 5::numeric, '% of rent', 'A late fee may not exceed 5% of the rent.', 'N.C. Gen. Stat. § 42-46(a)(1)', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_42/GS_42-46.html'),
  ('late_fee_grace_days', 'min', 5::numeric, 'days', 'A late fee may not be charged until at least 5 days after rent is due.', 'N.C. Gen. Stat. § 42-46(a)', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_42/GS_42-46.html'),
  ('deposit_max_months', 'max', 1.5::numeric, 'months of rent', 'A security deposit may not exceed 1.5 months of rent.', 'N.C. Gen. Stat. § 42-51(b)', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_42/GS_42-51.html'),
  ('deposit_return_days', 'max', 30::numeric, 'days', 'The deposit must be returned within 30 days after the tenancy ends.', 'N.C. Gen. Stat. § 42-52', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_42/GS_42-52.html'),
  ('notice_to_vacate_days', 'min', 7::numeric, 'days', 'Ending a month-to-month tenancy generally requires at least 7 days'' notice.', 'N.C. Gen. Stat. § 42-14', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_42/GS_42-14.html')
) AS v(topic, rule_kind, threshold_numeric, threshold_unit, summary, citation, url)
WHERE a.state_code = 'NC' AND a.act_key = 'residential' AND a.effective_year = 2026;

