SELECT a.id, 'MO', v.topic, v.rule_kind, v.threshold_numeric, v.threshold_unit, v.summary, v.citation, v.url, DATE '2026-06-11', 2026
FROM public.state_landlord_tenant_acts a CROSS JOIN (VALUES
  ('deposit_max_months', 'max', 2::numeric, 'months of rent', 'A security deposit may not exceed 2 months of rent.', 'RSMo 535.300.1', 'https://revisor.mo.gov/main/OneSection.aspx?section=535.300'),
  ('deposit_return_days', 'max', 30::numeric, 'days', 'The deposit must be returned within 30 days after the tenancy ends.', 'RSMo 535.300.3', 'https://revisor.mo.gov/main/OneSection.aspx?section=535.300'),
  ('notice_to_vacate_days', 'min', 30::numeric, 'days', 'Ending a month-to-month tenancy generally requires at least 30 days'' notice.', 'RSMo 441.060.1', 'https://revisor.mo.gov/main/OneSection.aspx?section=441.060')
) AS v(topic, rule_kind, threshold_numeric, threshold_unit, summary, citation, url)
WHERE a.state_code = 'MO' AND a.act_key = 'residential' AND a.effective_year = 2026;
